const b = $input.item.json.body || $input.item.json;
const url = (b.image_url || b.url || '').toString().trim();
if (!/^https?:\/\/.+\.(jpg|jpeg|png|pdf|gif|bmp|tiff)(\?.*)?$/i.test(url)) throw new Error('image_url invalide (formats acceptés : jpg, png, pdf, gif, bmp, tiff)');
const clean = s => (s || '').toString().replace(/<[^>]*>/g, '').trim().substring(0, 100);
return { image_url: url, type_attendu: clean(b.type || 'auto') };

const r = $input.item.json;
if (r.IsErroredOnProcessing) throw new Error('OCR échoué : ' + (Array.isArray(r.ErrorMessage) ? r.ErrorMessage.join(' ') : r.ErrorMessage || 'erreur inconnue'));
const texte = (r.ParsedResults || []).map(p => p.ParsedText || '').join('\n').replace(/\r/g, '').trim();
if (!texte) throw new Error('Aucun texte détecté dans le document');
return { texte: texte.substring(0, 6000), type_attendu: $('Valider l\'image').item.json.type_attendu, image_url: $('Valider l\'image').item.json.image_url };

const src = $('Extraire le texte OCR').item.json;
let d;
try { d = JSON.parse($input.item.json.message.content.match(/\{[\s\S]*\}/)[0]); }
catch(e) { d = { type: 'autre', titre: 'Document', infos_cles: [] }; }
return {
  type: d.type || 'autre',
  titre: (d.titre || 'Document').substring(0, 255),
  emetteur: (d.emetteur || '').substring(0, 255),
  date_doc: (d.date && /^\d{4}-\d{2}-\d{2}$/.test(d.date)) ? d.date : null,
  montant: (typeof d.montant === 'number') ? d.montant : null,
  infos_cles: JSON.stringify(d.infos_cles || []),
  a_conserver: d.a_conserver === true,
  contenu_ocr: src.texte,
  image_url: src.image_url
};
